// 生成HTML内容
const input = $input.all()[0].json;
const text = input.content || '';
const author = input.author?.username || 'User';
const guildName = input.guild?.name || 'Discord';

// 处理文本 - 转义HTML并格式化
const escapeHtml = (str) => {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
};

let formattedText = escapeHtml(text);

// Markdown样式转换
formattedText = formattedText
  .replace(/```([\s\S]*?)```/g, '<pre class="code-block">$1</pre>')
  .replace(/`([^`]+)`/g, '<code class="inline-code">$1</code>')
  .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
  .replace(/\*([^*]+)\*/g, '<em>$1</em>')
  .replace(/__([^_]+)__/g, '<u>$1</u>')
  .replace(/~~([^~]+)~~/g, '<del>$1</del>')
  .replace(/\n/g, '<br>');

const timestamp = new Date().toLocaleString('zh-CN', {
  timeZone: 'Asia/Shanghai',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit'
});

const html = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body {
      font-family: 'Noto Sans SC', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      background: #36393f;
      padding: 20px;
      min-height: 100vh;
    }
    .message-container {
      background: #36393f;
      border-radius: 8px;
      padding: 16px 20px;
      max-width: 800px;
    }
    .header {
      display: flex;
      align-items: center;
      margin-bottom: 8px;
    }
    .avatar {
      width: 40px;
      height: 40px;
      border-radius: 50%;
      background: linear-gradient(135deg, #5865F2, #7289DA);
      display: flex;
      align-items: center;
      justify-content: center;
      color: white;
      font-weight: bold;
      font-size: 18px;
      margin-right: 16px;
      flex-shrink: 0;
    }
    .author-name {
      font-weight: 600;
      font-size: 16px;
      color: #ffffff;
      margin-right: 8px;
    }
    .timestamp {
      font-size: 12px;
      color: #72767d;
    }
    .content {
      font-size: 16px;
      line-height: 1.6;
      color: #dcddde;
      margin-left: 56px;
      word-wrap: break-word;
      white-space: pre-wrap;
    }
    .code-block {
      background: #2f3136;
      color: #b9bbbe;
      padding: 12px 16px;
      border-radius: 4px;
      font-family: 'Fira Code', 'Consolas', monospace;
      font-size: 14px;
      overflow-x: auto;
      margin: 8px 0;
      border-left: 3px solid #5865F2;
    }
    .inline-code {
      background: #2f3136;
      padding: 2px 6px;
      border-radius: 3px;
      font-family: 'Fira Code', monospace;
      font-size: 14px;
      color: #e8919d;
    }
    strong { color: #ffffff; font-weight: 600; }
    em { color: #b9bbbe; font-style: italic; }
    u { text-decoration: underline; color: #00aff4; }
    del { text-decoration: line-through; color: #72767d; }
    .footer {
      margin-top: 16px;
      padding-top: 12px;
      border-top: 1px solid #42454a;
      text-align: center;
      font-size: 11px;
      color: #72767d;
      margin-left: 56px;
    }
  </style>
</head>
<body>
  <div class="message-container">
    <div class="header">
      <div class="avatar">${author.charAt(0).toUpperCase()}</div>
      <span class="author-name">${escapeHtml(author)}</span>
      <span class="timestamp">${timestamp}</span>
    </div>
    <div class="content">${formattedText}</div>
    <div class="footer">via Discord Bot • ${escapeHtml(guildName)}</div>
  </div>
</body>
</html>`;

return {
  json: {
    html: html,
    channelId: input.channelId,
    originalMessage: text,
    author: author
  }
};
